#!/usr/bin/env bun

/**
 * Ralph Loop - Automated Claude Code Task Executor
 *
 * Based on Geoffrey Huntley's Ralph Wiggum technique:
 * - Fresh context per iteration (new Claude instance each time)
 * - Memory persists through files only (git, progress.txt)
 * - One task per iteration
 * - Completion signal terminates loop
 *
 * @see https://ghuntley.com/ralph/
 */

const CONFIG = {
  maxIterations: parseInt(Bun.argv[2] ?? "100"),
  delayBetweenIterations: 5000,
  logFile: "./loop.log",
  progressFile: "./.claude/progress.txt",
  completionSignal: "<promise>FINISHED</promise>",
};

const COLORS = {
  red: "\x1b[0;31m",
  green: "\x1b[0;32m",
  yellow: "\x1b[1;33m",
  blue: "\x1b[0;34m",
  reset: "\x1b[0m",
};

const TASK_PROMPT = `Read \`./.claude/progress.txt\`, pick the most important pending task, execute it, update the file, commit, and stop.

IMPORTANT RULES:
- Do NOT change logic, only migrate structure
- The source of truth is card-place, consult it only if in doubt
- The code has already been copied to this repository
- Everything must be migrated to the new architecture/Style Guide (./.claude/STYLE_GUIDE.md)

WORKFLOW:
1. Read progress.txt and identify the next pending task
2. If NO pending tasks exist, output exactly: <promise>FINISHED</promise> and stop
3. If there is a task:
   a. Update task status to "in progress" in progress.txt
   b. Execute migration following STYLE_GUIDE.md
   c. Launch a review agent (Task tool with subagent_type=Explore) to verify the work
   d. Review output and consider improvements
   e. Implement corrections if needed
   f. Update progress.txt marking task as completed
   g. Commit changes
   h. Stop

CRITICAL: If all tasks are completed, you MUST output: <promise>FINISHED</promise>`;

async function log(message: string, color?: string): Promise<void> {
  const timestamp = new Date().toISOString().replace("T", " ").slice(0, 19);
  const line = `[${timestamp}] ${message}`;
  const coloredLine = color ? `${color}${line}${COLORS.reset}` : line;

  console.log(coloredLine);

  const file = Bun.file(CONFIG.logFile);
  const existingContent = (await file.exists()) ? await file.text() : "";
  await Bun.write(CONFIG.logFile, existingContent + line + "\n");
}

async function checkDependencies(): Promise<void> {
  const claudeCheck = Bun.spawn(["which", "claude"], {
    stdout: "pipe",
    stderr: "pipe",
  });
  await claudeCheck.exited;

  if (claudeCheck.exitCode !== 0) {
    await log("ERROR: 'claude' command not found. Install Claude Code CLI.", COLORS.red);
    process.exit(1);
  }

  const progressFile = Bun.file(CONFIG.progressFile);
  if (!(await progressFile.exists())) {
    await log(`ERROR: Progress file not found: ${CONFIG.progressFile}`, COLORS.red);
    process.exit(1);
  }
}

function printHeader(): void {
  console.log();
  console.log(`${COLORS.blue}==========================================${COLORS.reset}`);
  console.log(`${COLORS.blue}   Ralph Loop - Bun.js Edition${COLORS.reset}`);
  console.log(`${COLORS.blue}==========================================${COLORS.reset}`);
  console.log(`Max iterations: ${COLORS.yellow}${CONFIG.maxIterations}${COLORS.reset}`);
  console.log(`Log file: ${COLORS.yellow}${CONFIG.logFile}${COLORS.reset}`);
  console.log(`Delay between iterations: ${COLORS.yellow}${CONFIG.delayBetweenIterations / 1000}s${COLORS.reset}`);
  console.log();
}

async function runIteration(iteration: number): Promise<{ output: string; exitCode: number }> {
  await log("Executing Claude Code...");

  const proc = Bun.spawn(["claude", "-p", TASK_PROMPT], {
    stdout: "pipe",
    stderr: "pipe",
  });

  let output = "";
  const decoder = new TextDecoder();

  const stdoutReader = (async () => {
    for await (const chunk of proc.stdout) {
      const text = decoder.decode(chunk);
      process.stdout.write(text);
      output += text;
    }
  })();

  const stderrReader = (async () => {
    for await (const chunk of proc.stderr) {
      const text = decoder.decode(chunk);
      process.stderr.write(text);
      output += text;
    }
  })();

  await Promise.all([stdoutReader, stderrReader]);
  const exitCode = await proc.exited;

  return { output, exitCode };
}

async function main(): Promise<void> {
  let cleanupCalled = false;

  const cleanup = async () => {
    if (cleanupCalled) return;
    cleanupCalled = true;
    console.log();
    await log("Script interrupted. Cleaning up...");
    process.exit(0);
  };

  process.on("SIGINT", cleanup);
  process.on("SIGTERM", cleanup);

  await checkDependencies();
  printHeader();

  await log("Starting automated task loop...");

  for (let iteration = 1; iteration <= CONFIG.maxIterations; iteration++) {
    console.log();
    console.log(`${COLORS.green}==========================================${COLORS.reset}`);
    await log(`Iteration #${iteration} / ${CONFIG.maxIterations}`, COLORS.green);
    console.log(`${COLORS.green}==========================================${COLORS.reset}`);
    console.log();

    const { output, exitCode } = await runIteration(iteration);

    if (exitCode === 0) {
      await log("Claude Code execution completed successfully", COLORS.green);
    } else {
      await log(`Claude Code exited with status ${exitCode}, checking output...`, COLORS.yellow);
    }

    if (output.includes(CONFIG.completionSignal)) {
      console.log();
      console.log(`${COLORS.green}==========================================${COLORS.reset}`);
      await log("ALL TASKS COMPLETED!", COLORS.green);
      await log(`Total iterations: ${iteration}`, COLORS.green);
      console.log(`${COLORS.green}==========================================${COLORS.reset}`);
      process.exit(0);
    }

    if (/error|failed|exception/i.test(output)) {
      await log("Warning: Potential errors detected in output.", COLORS.yellow);
    }

    if (iteration < CONFIG.maxIterations) {
      console.log();
      await log(`Waiting ${CONFIG.delayBetweenIterations / 1000} seconds before next iteration...`);
      await Bun.sleep(CONFIG.delayBetweenIterations);
    }
  }

  console.log();
  console.log(`${COLORS.red}==========================================${COLORS.reset}`);
  await log(`MAX ITERATIONS REACHED (${CONFIG.maxIterations})`, COLORS.red);
  await log("Loop stopped - tasks may still be pending", COLORS.red);
  console.log(`${COLORS.red}==========================================${COLORS.reset}`);
  process.exit(1);
}

main();

