async function streamToOutput(
  stream: ReadableStream<Uint8Array>,
  target: NodeJS.WriteStream,
  decoder: TextDecoder,
  appendTo: { value: string }
): Promise<void> {
  const reader = stream.getReader();
  try {
    while (true) {
      const { done, value } = await reader.read();
      if (done) break;
      const text = decoder.decode(value, { stream: true });
      target.write(text);
      appendTo.value += text;
    }
    const final = decoder.decode();
    if (final) {
      target.write(final);
      appendTo.value += final;
    }
  } catch (err) {
    logSync(`Error reading stream: ${err}`, COLORS.red);
  } finally {
    reader.releaseLock();
  }
}

async function runIteration(): Promise<{ output: string; exitCode: number }> {
  await log("Executing Claude Code...");

  const proc = Bun.spawn(["claude", "-p", TASK_PROMPT], {
    stdout: "pipe",
    stderr: "pipe",
  });

  const output = { value: "" };

  const stdoutPromise = streamToOutput(
    proc.stdout,
    process.stdout,
    new TextDecoder(),
    output
  );

  const stderrPromise = streamToOutput(
    proc.stderr,
    process.stderr,
    new TextDecoder(),
    output
  );

  await Promise.all([stdoutPromise, stderrPromise, proc.exited]);

  return { output: output.value, exitCode: proc.exitCode ?? 1 };
}

